const task = $('Lock Task').first().json;
const engines = ['google', 'bing', 'duckduckgo', 'brave'];
let finalResult = null;
let usedEngine = null;

for (const engine of engines) {
  try {
    const response = await $helpers.httpRequest({
      method: 'GET',
      url: 'http://searxng:8080/search',
      qs: {
        q: task.keyword,
        format: 'json',
        engines: engine,
        language: task.lang || 'cs-CZ'
      },
      timeout: 10000,
      json: true
    });

    if (response && Array.isArray(response.results) && response.results.length > 0) {
      finalResult = response;
      usedEngine = engine;
      break;
    }
  } catch (error) {
    console.log(`Engine ${engine} failed:`, error.message);
  }
}

if (!finalResult) {
  return [{ json: { error: 'All engines failed or returned empty results', results: [] } }];
}
finalResult.used_engine = usedEngine;
return [{ json: finalResult }];

// Parsujeme json odpověď od SearxNG
const r = $input.first().json;
const task = $('Lock Task').first().json;

// Ujistíme se testem, že searxNG našel výsledky bez chyby
const ok = Array.isArray(r.results) && r.results.length > 0;

const esc = v => v == null ? null : String(v).replace(/'/g, "''").substring(0, 500);
const escUrl = v => v == null ? null : String(v).replace(/'/g, "''").substring(0, 2000);

// Iterujeme přes pole results přicházejících ze SearxNG
const organic = ok ? r.results.map((o, index) => ({
  ...task, 
  position: index + 1, 
  title: esc(o.title), 
  description: String(o.content||'').replace(/'/g,"''").substring(0,1000), 
  url: escUrl(o.url)
})) : [];

// PAA nebývá v SearxNG JSON odpovědích snadno generováno z Googlu (často null).
const paa = []; 
// Related / Návrhy SearxNG ale umí napojit z pole suggestions
const related = ok ? (r.suggestions||[]).map((s, i) => ({
  ...task, position: i+1, query: esc(s)
})) : [];

// Zpráva chyby, pokud Google neodpověděl jak měl 
const errMsg = ok ? null : (r.unresponsive_engines && r.unresponsive_engines.length > 0 ? "Všechny enginy selhaly" : (r.error || "empty results"));
const used_engine = r.used_engine || null;

return [{
  json: {
    task_id: task.id, job_id: task.job_id, client_id: task.client_id,
    keyword: task.keyword, attempts: task.attempts,
    is_success: ok, error: errMsg,
    engine: used_engine,
    organic, paa, related
  }
}];

const d = $input.first().json;
const esc = v => v == null ? 'NULL' : `'${v}'`;
let oSql = 'SELECT 1';
if (d.organic && d.organic.length > 0) {
  const v = d.organic.map(r => `(${r.id},${r.job_id},${r.client_id||'NULL'},${esc(r.keyword)},${r.position},${esc(r.title)},${esc(r.description)},${esc(r.url)},${esc(d.engine)},NOW())`).join(',');
  oSql = `INSERT INTO seo_kws.serp_organic (task_id,job_id,client_id,keyword,position,title,description,url,engine,scraped_at) VALUES ${v}`;
}
let pSql = 'SELECT 1';
if (d.paa && d.paa.length > 0) {
  const v = d.paa.map(r => `(${r.id},${r.job_id},${r.client_id||'NULL'},${esc(r.keyword)},${r.position},${esc(r.question)},${esc(d.engine)},NOW())`).join(',');
  pSql = `INSERT INTO seo_kws.serp_paa (task_id,job_id,client_id,keyword,position,question,engine,scraped_at) VALUES ${v}`;
}
let rSql = 'SELECT 1';
if (d.related && d.related.length > 0) {
  const v = d.related.map(r => `(${r.id},${r.job_id},${r.client_id||'NULL'},${esc(r.keyword)},${r.position},${esc(r.query)},${esc(d.engine)},NOW())`).join(',');
  rSql = `INSERT INTO seo_kws.serp_related (task_id,job_id,client_id,keyword,position,query,engine,scraped_at) VALUES ${v}`;
}
return [{json: {...d, o_sql:oSql, p_sql:pSql, r_sql:rSql}}];

